checker_dsl:
EXISTS (`method call MC`) {
  AND {
    (`MC is a call to a method named "equals" with exactly one parameter of type java.lang.Object and return type boolean`),
    NOT {
      OR {
        EXISTS (`method call PARENT_MC`) {
          AND {
            (`PARENT_MC is an ancestor of MC in the AST`),
            (`the name of the method called by PARENT_MC starts with "assert"`)
          }
        },
        (`the statement that immediately contains MC is an assert statement`)
      }
    },
    EXISTS (`reference type RECV_TP`) {
      AND {
        OR {
          AND {
            (`the method called by MC is declared in java.lang.Object`),
            (`RECV_TP is the compile-time type of the receiver expression of MC`)
          },
          AND {
            NOT { (`the method called by MC is declared in java.lang.Object`) },
            (`RECV_TP is the declaring type of the method called by MC`)
          }
        },
        EXISTS (`reference type ARG_TP`) {
          AND {
            (`ARG_TP is the compile-time type of the first argument expression passed to MC`),
            NOT {
              EXISTS (`reference type COMMON`) {
                AND {
                  (`COMMON is a subtype of RECV_TP`),
                  (`COMMON is a subtype of ARG_TP`),
                  NOT { (`COMMON is java.lang.Object`) }
                }
              }
            }
          }
        }
      }
    }
  }
}
